import logo from "./logo.svg";
import "./App.css";
import { useState } from "react";

import Serial from "./Serial.js";

function App() {
  const [deviceState, setDeviceState] = useState("connect");
  return (
    <div className="App">
      <header className="App-header"></header>
      <Serial deviceState={deviceState} setDeviceState={setDeviceState} />
    </div>
  );
}

export default App;
